#include <stdio.h>
#include <string.h>

int main() {
    int T = 1;
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char matrix[N][M];
        for (int i = 0; i < N; i++) {
            scanf(" %s", matrix[i]);
        }
        int ans = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                for (int h = 1; i + h - 1 < N && j + h - 1 < M; h++) {
                    int flag = 1;
                    for (int x = 0; x < h; x++) {
                        for (int y = x; y < h; y++) {
                            if (matrix[i + x][j + y] != '1') {
                                flag = 0;
                                break;
                            }
                        }
                        if (!flag) break;
                    }
                    if (flag) ans++;
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

