import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = 1;
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            char[][] matrix = new char[N][M];
            for (int i = 0; i < N; i++) {
                String s = sc.next();
                for (int j = 0; j < M; j++) {
                    matrix[i][j] = s.charAt(j);
                }
            }
            int ans = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    for (int h = 1; i + h - 1 < N && j + h - 1 < M; h++) {
                        int flag = 1;
                        for (int x = 0; x < h; x++) {
                            for (int y = x; y < h; y++) {
                                if (matrix[i + x][j + y] != '1') {
                                    flag = 0;
                                    break;
                                }
                            }
                            if (flag == 0) break;
                        }
                        if (flag == 1) ans++;
                    }
                }
            }
            System.out.println(ans);
        }
    }
}

