T = 1
for _ in range(T):
    N, M = map(int, input().split())
    matrix = [list(input().rstrip()) for _ in range(N)]
    ans = 0
    for i in range(N):
        for j in range(M):
            for h in range(1, min(N - i, M - j) + 1):
                flag = 1
                for x in range(h):
                    for y in range(x, h):
                        if matrix[i + x][j + y] != '1':
                            flag = 0
                            break
                    if flag == 0: break
                if flag: ans += 1
    print(ans)

